INSERT INTO words (word, category_id, position, tag, zh, en, example_en, example_zh, synonyms) VALUES
  ('come', 'op', 1, 'OP', '来；到来；走近说话者或目标', 'move toward the speaker or toward a named place', 'Come to the table before the food is cold.', '饭菜变凉前到桌边来。', '[{"w":"get","def":"get: 相关的动作或关系词","vs":"与 come 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"get\" / \"come\" 的替换练习"},{"w":"give","def":"give: 可帮助扩展句型的基础词","vs":"与 come 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"give\" / \"come\" 的替换练习"}]'),
  ('get', 'op', 2, 'OP', '得到；获得；变得；去取', 'receive, obtain, become, or fetch something', 'I will get some water for the child.', '我会给这个孩子取一些水。', '[{"w":"come","def":"come: 相关的动作或关系词","vs":"与 get 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"come\" / \"get\" 的替换练习"},{"w":"give","def":"give: 可帮助扩展句型的基础词","vs":"与 get 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"give\" / \"get\" 的替换练习"},{"w":"go","def":"go: 同一组 Basic English 操作词","vs":"与 get 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"go\" / \"get\" 的替换练习"}]'),
  ('give', 'op', 3, 'OP', '给；交给；提供', 'put something in another person''s possession or care', 'Give the note to your mother after class.', '下课后把这张便条给你母亲。', '[{"w":"get","def":"get: 相关的动作或关系词","vs":"与 give 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"get\" / \"give\" 的替换练习"},{"w":"go","def":"go: 可帮助扩展句型的基础词","vs":"与 give 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"go\" / \"give\" 的替换练习"},{"w":"keep","def":"keep: 同一组 Basic English 操作词","vs":"与 give 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"keep\" / \"give\" 的替换练习"}]'),
  ('go', 'op', 4, 'OP', '去；离开；进行', 'move away, travel, or continue in a direction', 'We go across the road when the light is green.', '绿灯时我们穿过马路。', '[{"w":"give","def":"give: 相关的动作或关系词","vs":"与 go 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"give\" / \"go\" 的替换练习"},{"w":"keep","def":"keep: 可帮助扩展句型的基础词","vs":"与 go 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"keep\" / \"go\" 的替换练习"},{"w":"let","def":"let: 同一组 Basic English 操作词","vs":"与 go 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"let\" / \"go\" 的替换练习"}]'),
  ('keep', 'op', 5, 'OP', '保持；保留；照管', 'hold something, continue a state, or take care of it', 'Keep the window open while the room is warm.', '房间暖和时让窗户保持开着。', '[{"w":"go","def":"go: 相关的动作或关系词","vs":"与 keep 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"go\" / \"keep\" 的替换练习"},{"w":"let","def":"let: 可帮助扩展句型的基础词","vs":"与 keep 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"let\" / \"keep\" 的替换练习"},{"w":"make","def":"make: 同一组 Basic English 操作词","vs":"与 keep 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"make\" / \"keep\" 的替换练习"}]');
